const input = $input.first().json;
return [{ json: {
  filter_by_type: input.filter_by_type || null,
  filter_by_ids:  input.filter_by_ids ? JSON.parse(input.filter_by_ids) : null,
  hostname:       input.hostname || input.wer || null,
  netbox_token:   '6e517f4e4fd4b3f3d3de63770bd79e6faacf0fe4',
  netbox_base:    'http://10.1.1.104'
} }];

// Merge and normalize all NetBox results into unified format
// Sources:
//   allItems[0] = VMs       (virtualization/virtual-machines, type=vm)
//   allItems[1] = LXCs      (virtualization/virtual-machines?cf_vm_type=lxc, type=lxc)
//   allItems[2] = Physical  (dcim/devices, device_class=physical)
//   allItems[3] = Virtual   (dcim/devices?virtual_chassis=true, device_class=virtual_device)

const allItems = $input.all();

function extractIP(primaryIp) {
  if (!primaryIp || !primaryIp.address) return null;
  return primaryIp.address.split('/')[0];
}

function getOsFamily(platform) {
  if (!platform) return 'unknown';
  const s = ((platform.slug || platform.name || '')).toLowerCase();
  if (/debian|ubuntu|raspi|kali|mint|parrot|pop/.test(s))  return 'apt';
  if (/alpine/.test(s))                                     return 'apk';
  if (/arch|manjaro|endeavour/.test(s))                     return 'pacman';
  if (/fedora|rhel|centos|rocky|alma|oracle/.test(s))       return 'dnf';
  if (/suse|opensuse/.test(s))                              return 'zypper';
  if (/routeros|mikrotik/.test(s))                          return 'routeros';
  if (/openwrt/.test(s))                                    return 'opkg';
  if (/vyos/.test(s))                                       return 'vyos';
  if (/opnsense|pfsense/.test(s))                           return 'bsd';
  if (/windows/.test(s))                                    return 'windows';
  return 'unknown';
}

function normalizePlatform(raw) {
  if (!raw) return null;
  return { name: raw.name || '', slug: raw.slug || '' };
}

// Normalize a VM/LXC (virtualization endpoint)
function normalizeVM(vm, typeOverride) {
  const cfVmType = vm.custom_fields && vm.custom_fields.vm_type;
  const type     = typeOverride || (cfVmType === 'lxc' ? 'lxc' : 'vm');
  const platform = normalizePlatform(vm.platform);
  return {
    id:           vm.id,
    name:         vm.name,
    ip:           extractIP(vm.primary_ip4 || vm.primary_ip),
    type,                          // 'lxc' | 'vm'
    device_class: 'virtual',       // virtualization endpoint
    platform,
    os_family:    getOsFamily(platform),
    ssh_user:     (vm.custom_fields && vm.custom_fields.ssh_user)     || 'root',
    ssh_password: (vm.custom_fields && vm.custom_fields.ssh_password) || '',
    cluster:      vm.cluster ? vm.cluster.name : null,
    status:       vm.status  ? vm.status.value  : 'unknown'
  };
}

// Normalize a physical or virtual-chassis device (dcim endpoint)
function normalizeDevice(dev, isVirtualChassis) {
  const platform = normalizePlatform(dev.platform);
  return {
    id:           dev.id,
    name:         dev.name,
    ip:           extractIP(dev.primary_ip4 || dev.primary_ip),
    type:         'device',
    device_class: isVirtualChassis ? 'virtual_device' : 'physical',
    platform,
    os_family:    getOsFamily(platform),
    ssh_user:     (dev.custom_fields && dev.custom_fields.ssh_user)     || 'root',
    ssh_password: (dev.custom_fields && dev.custom_fields.ssh_password) || '',
    cluster:      dev.site ? dev.site.name : null,
    status:       dev.status ? dev.status.value : 'unknown'
  };
}

const normalized = [];

// allItems[0] = VMs, allItems[1] = LXCs → virtualization
for (let idx = 0; idx < 2; idx++) {
  const item = allItems[idx];
  if (!item || !item.json || !item.json.results) continue;
  const typeOverride = idx === 1 ? 'lxc' : null;
  for (const entry of item.json.results) {
    normalized.push(normalizeVM(entry, typeOverride));
  }
}

// allItems[2] = Physical devices
if (allItems[2] && allItems[2].json && allItems[2].json.results) {
  for (const dev of allItems[2].json.results) {
    normalized.push(normalizeDevice(dev, false));
  }
}

// allItems[3] = Virtual-chassis devices
if (allItems[3] && allItems[3].json && allItems[3].json.results) {
  for (const dev of allItems[3].json.results) {
    normalized.push(normalizeDevice(dev, true));
  }
}

// Deduplicate by type+id
const seen   = new Set();
const deduped = normalized.filter(item => {
  const key = `${item.type}_${item.id}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return [{ json: { systems: deduped, total: deduped.length } }];

const data   = $input.first().json;
const fp     = $('🔧 Parse Filter Parameters').first().json;
const systems = data.systems || [];

let filtered = [...systems];

if (fp.filter_by_type && fp.filter_by_type !== '') {
  filtered = filtered.filter(s => s.type === fp.filter_by_type);
}
if (fp.filter_by_ids && Array.isArray(fp.filter_by_ids) && fp.filter_by_ids.length > 0) {
  const idSet = new Set(fp.filter_by_ids.map(String));
  filtered = filtered.filter(s => idSet.has(String(s.id)));
}
if (fp.hostname && fp.hostname !== '') {
  const hn = fp.hostname.toLowerCase();
  filtered = filtered.filter(s => s.name && s.name.toLowerCase().includes(hn));
}

const withIp = filtered.filter(s => s.ip);

if (withIp.length === 0) {
  return [{ json: { id: null, name: 'NO_SYSTEMS_FOUND', ip: null, type: null,
    device_class: null, platform: null, os_family: 'unknown',
    ssh_user: null, ssh_password: null, cluster: null, _empty: true } }];
}

return withIp.map(system => ({ json: system }));
